<template>
  <div class="resume-verify-page min-h-screen bg-slate-50 text-slate-800">
    <header class="gradient-hero flowing-gradient-cosmic hero-header">
      <div class="hero-inner">
        <span class="hero-eyebrow">DUT BLOCKCHAIN RECRUITMENT</span>
        <h1 class="hero-title">简历投递</h1>
        <p class="hero-subtitle">上传 credential.json 后完成 ZKP 校验，再提交报名信息。</p>
      </div>
    </header>

    <main class="mx-auto max-w-6xl px-4 py-10 sm:px-6 lg:px-8">
      <section class="grid gap-8 lg:grid-cols-[1fr_320px]">
        <article class="rounded-2xl border border-slate-200 bg-white p-6 shadow-[0_12px_36px_rgba(15,23,42,0.08)] sm:p-8">
          <div class="step-block">
            <h2 class="step-title">第一步：上传密钥文件</h2>
            <input type="file" accept=".json" class="field-file" @change="onCredentialChange">
          </div>

          <div class="step-block">
            <h2 class="step-title">第二步：zkp校验</h2>
            <div class="grid gap-4 sm:grid-cols-2">
              <div class="space-y-2">
                <label class="block text-sm text-slate-700">姓名</label>
                <input v-model="form.username" class="field-input" disabled>
              </div>
              <div class="space-y-2">
                <label class="block text-sm text-slate-700">学号</label>
                <input v-model="form.studentId" class="field-input" disabled>
              </div>
            </div>

            <div class="mt-4">
              <button class="action-btn action-btn-primary" :disabled="!hasCredential || isVerifying" @click="doChallenge">
                {{ isVerifying ? '校验中...' : '执行校验' }}
              </button>
            </div>

            <p v-if="challengeResult" class="mt-3 rounded-lg border border-emerald-300 bg-emerald-50 px-3 py-2 text-sm text-emerald-700">
              校验通过，challengeId: {{ challengeResult.challengeId }}
            </p>
          </div>

          <form class="step-block" @submit.prevent="doSubmit">
            <h2 class="step-title">第三步：填写报名信息并提交</h2>
            <div class="space-y-4">
              <div class="space-y-2">
                <label class="block text-sm text-slate-700">联系方式 *</label>
                <input v-model.trim="form.contact" class="field-input" placeholder="手机号 / 微信 / 邮箱" required>
              </div>
              <div class="space-y-2">
                <label class="block text-sm text-slate-700">邮箱 *</label>
                <input v-model.trim="form.email" type="email" class="field-input" placeholder="请输入常用邮箱" required>
              </div>
              <div class="space-y-2">
                <label class="block text-sm text-slate-700">技术栈 *</label>
                <textarea v-model.trim="form.techStack" class="field-input field-textarea" rows="3" required />
              </div>
              <div class="space-y-2">
                <label class="block text-sm text-slate-700">项目经历 *</label>
                <textarea v-model.trim="form.projectExp" class="field-input field-textarea" rows="4" required />
              </div>
              <div class="space-y-2">
                <label class="block text-sm text-slate-700">在校经历 *</label>
                <textarea v-model.trim="form.campusExp" class="field-input field-textarea" rows="4" required />
              </div>
              <div class="space-y-2">
                <label class="block text-sm text-slate-700">补充说明</label>
                <textarea v-model.trim="form.additional" class="field-input field-textarea" rows="3" />
              </div>
              <div class="space-y-2">
                <label class="block text-sm text-slate-700">照片（JPG/PNG，2MB 内）</label>
                <input type="file" accept="image/jpeg,image/png" class="field-file" @change="onPhotoChange">
              </div>
            </div>

            <p v-if="errorMessage" class="mt-4 rounded-lg border border-red-300 bg-red-50 px-3 py-2 text-sm text-red-700">
              {{ errorMessage }}
            </p>

            <div class="mt-6">
              <button class="action-btn action-btn-success" type="submit" :disabled="!canSubmit || isSubmitting">
                {{ isSubmitting ? '提交中...' : '提交报名' }}
              </button>
            </div>
          </form>
        </article>

        <aside class="space-y-6">
          <section class="rounded-2xl border border-slate-200 bg-white p-6 shadow-[0_10px_28px_rgba(15,23,42,0.06)]">
            <h2 class="text-lg font-semibold text-slate-900">注意事项</h2>
            <ul class="mt-4 space-y-2 text-sm leading-6 text-slate-600">
              <li>请先在登录页生成 credential.json，再到此页上传。</li>
              <li>校验通过后才能提交报名信息。</li>
              <li>提交成功后会跳转到完成页。</li>
            </ul>
          </section>
        </aside>
      </section>
    </main>
  </div>
</template>

<script setup lang="ts">
import axios from 'axios'
import { computed, reactive, ref } from 'vue'
import { useRouter } from 'vue-router'
import { challenge, verifyAndSubmit } from '@/api/zkpAuth'
import { bnToHex, computeS, generateRandomR, parseHex } from '@/utils/zkp'

interface CredentialFile {
  username: string
  studentId: string
  x: string
  createdAt: number
}

interface ResumeVerifyForm {
  username: string
  studentId: string
  contact: string
  email: string
  techStack: string
  projectExp: string
  campusExp: string
  additional: string
  photoBase64: string
}

interface ChallengeState {
  challengeId: string
  c: string
  s: string
  clientR: string
}

const router = useRouter()
const credential = ref<CredentialFile | null>(null)
const challengeResult = ref<ChallengeState | null>(null)
const isVerifying = ref(false)
const isSubmitting = ref(false)
const errorMessage = ref('')

const form = reactive<ResumeVerifyForm>({
  username: '',
  studentId: '',
  contact: '',
  email: '',
  techStack: '',
  projectExp: '',
  campusExp: '',
  additional: '',
  photoBase64: ''
})

const hasCredential = computed(() => Boolean(credential.value?.x))
const canSubmit = computed(() => hasCredential.value && Boolean(challengeResult.value))

const isValidEmail = (value: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value)

const resolveErrorMessage = (error: unknown, fallback: string) => {
  if (!axios.isAxiosError(error)) {
    return error instanceof Error ? error.message : fallback
  }

  if (!error.response) {
    if (typeof navigator !== 'undefined' && navigator.onLine === false) {
      return '当前网络已断开，请连接网络后重试。'
    }
    return '无法连接到认证服务，请稍后重试。'
  }

  const status = error.response.status
  const responseData = error.response.data as
    | string
    | {
      message?: string
      msg?: string
      error?: string | { message?: string; msg?: string }
      data?: { message?: string; msg?: string }
    }
    | undefined

  const backendMessage = (() => {
    if (typeof responseData === 'string') {
      return responseData
    }
    if (!responseData || typeof responseData !== 'object') {
      return ''
    }

    if (typeof responseData.message === 'string') return responseData.message
    if (typeof responseData.msg === 'string') return responseData.msg
    if (typeof responseData.error === 'string') return responseData.error

    if (responseData.error && typeof responseData.error === 'object') {
      if (typeof responseData.error.message === 'string') return responseData.error.message
      if (typeof responseData.error.msg === 'string') return responseData.error.msg
    }

    if (responseData.data && typeof responseData.data === 'object') {
      if (typeof responseData.data.message === 'string') return responseData.data.message
      if (typeof responseData.data.msg === 'string') return responseData.data.msg
    }

    return ''
  })()

  if (backendMessage && backendMessage.trim()) {
    return backendMessage.trim()
  }

  if (status === 400) {
    return '请求参数无效，请确认上传的凭证与填写信息一致。'
  }

  if (status === 401 || status === 403) {
    return '校验未通过，请重新执行 ZKP 校验。'
  }

  if (status === 404) {
    return '校验会话不存在，请重新执行校验。'
  }

  if (status >= 500) {
    return '服务暂时不可用，请稍后再试。'
  }

  return fallback
}

const onCredentialChange = (event: Event) => {
  const target = event.target as HTMLInputElement
  const file = target.files?.[0]
  if (!file) {
    return
  }

  const reader = new FileReader()
  reader.onload = (ev) => {
    try {
      const payload = JSON.parse(String(ev.target?.result ?? '{}')) as Partial<CredentialFile>
      if (!payload.username || !payload.studentId || !payload.x) {
        errorMessage.value = '密钥文件格式错误，请重新选择。'
        return
      }

      credential.value = {
        username: payload.username,
        studentId: payload.studentId,
        x: payload.x,
        createdAt: Number(payload.createdAt || Date.now())
      }

      form.username = payload.username
      form.studentId = payload.studentId
      challengeResult.value = null
      errorMessage.value = ''
    } catch {
      errorMessage.value = '解析密钥文件失败，请确认是 credential.json。'
    }
  }
  reader.readAsText(file)
}

const onPhotoChange = (event: Event) => {
  const target = event.target as HTMLInputElement
  const file = target.files?.[0]
  if (!file) {
    return
  }

  if (file.size > 2 * 1024 * 1024) {
    errorMessage.value = '照片不能超过 2MB。'
    return
  }

  const reader = new FileReader()
  reader.onload = (ev) => {
    const result = String(ev.target?.result ?? '')
    form.photoBase64 = result.includes(',') ? result.split(',')[1] : result
  }
  reader.readAsDataURL(file)
}

const doChallenge = async () => {
  if (!credential.value) {
    errorMessage.value = '请先上传 credential.json。'
    return
  }

  errorMessage.value = ''
  isVerifying.value = true
  try {
    const { r, R } = generateRandomR()
    const clientR = bnToHex(R)
    const response = await challenge({
      username: form.username,
      studentId: form.studentId,
      clientR
    })

    const c = response.data.c
    const s = bnToHex(computeS(r, parseHex(credential.value.x), parseHex(c)))
    challengeResult.value = {
      challengeId: response.data.challengeId,
      c,
      s,
      clientR
    }
  } catch (error: unknown) {
    challengeResult.value = null
    errorMessage.value = resolveErrorMessage(error, '校验失败，请重试。')
  } finally {
    isVerifying.value = false
  }
}

const doSubmit = async () => {
  errorMessage.value = ''

  if (!challengeResult.value) {
    errorMessage.value = '请先完成校验。'
    return
  }

  if (!form.contact || !form.email || !form.techStack || !form.projectExp || !form.campusExp) {
    errorMessage.value = '请先完整填写报名信息。'
    return
  }

  if (!isValidEmail(form.email)) {
    errorMessage.value = '邮箱格式不正确。'
    return
  }

  isSubmitting.value = true
  try {
    await verifyAndSubmit({
      challengeId: challengeResult.value.challengeId,
      s: challengeResult.value.s,
      clientR: challengeResult.value.clientR,
      username: form.username,
      studentId: form.studentId,
      contact: form.contact,
      email: form.email,
      techStack: form.techStack,
      projectExp: form.projectExp,
      campusExp: form.campusExp,
      additional: form.additional,
      photoBase64: form.photoBase64
    })
    router.push('/resume-success')
  } catch (error: unknown) {
    errorMessage.value = resolveErrorMessage(error, '提交失败，请稍后重试。')
  } finally {
    isSubmitting.value = false
  }
}
</script>

<style scoped>
.step-block {
  padding-bottom: 1.25rem;
  margin-bottom: 1.25rem;
  border-bottom: 1px solid #e2e8f0;
}

.step-block:last-of-type {
  border-bottom: none;
  margin-bottom: 0;
}

.step-title {
  font-size: 1.05rem;
  font-weight: 700;
  margin-bottom: 0.9rem;
  color: #0f172a;
}

.field-input {
  width: 100%;
  border-radius: 0.75rem;
  border: 1px solid rgb(203, 213, 225);
  background: rgb(255, 255, 255);
  padding: 0.72rem 0.95rem;
  color: rgb(15, 23, 42);
  outline: none;
  transition: border-color 0.2s ease, box-shadow 0.2s ease;
}

.field-input::placeholder {
  color: rgb(148, 163, 184);
}

.field-input:focus {
  border-color: rgb(59, 130, 246);
  box-shadow: 0 0 0 3px rgba(59, 130, 246, 0.14);
}

.field-file {
  width: 100%;
  border-radius: 0.75rem;
  border: 1px solid rgb(203, 213, 225);
  background: rgb(255, 255, 255);
  color: rgb(51, 65, 85);
  padding: 0.55rem 0.8rem;
}

.field-textarea {
  min-height: 7rem;
  resize: vertical;
}

.action-btn {
  border: none;
  border-radius: 0.75rem;
  padding: 0.72rem 1rem;
  font-size: 0.95rem;
  font-weight: 600;
  cursor: pointer;
  transition: all 0.2s ease;
}

.action-btn:disabled {
  opacity: 0.65;
  cursor: not-allowed;
}

.action-btn-primary {
  color: #fff;
  background: linear-gradient(135deg, #0f172a, #1e40af);
}

.action-btn-success {
  color: #fff;
  width: 100%;
  background: linear-gradient(135deg, #065f46, #059669);
}

.action-btn-primary:hover:not(:disabled),
.action-btn-success:hover:not(:disabled) {
  transform: translateY(-1px);
}
</style>
